UPDATE customer_info
SET
unit_name = CASE id

    WHEN #{item.id} THEN #{item.unitName}

END,
disabled_flag = CASE id

    WHEN #{item.id} THEN #{item.disabledFlag}

END,
unit_alias = CASE id

    WHEN #{item.id} THEN #{item.unitAlias}

END,
contact_person = CASE id

    WHEN #{item.id} THEN #{item.contactPerson}

END,
contact_phone = CASE id

    WHEN #{item.id} THEN #{item.contactPhone}

END,
region = CASE id

    WHEN #{item.id} THEN #{item.region}

END,
address = CASE id

    WHEN #{item.id} THEN #{item.address}

END,
mobile_phone = CASE id

    WHEN #{item.id} THEN #{item.mobilePhone}

END,
remarks = CASE id

    WHEN #{item.id} THEN #{item.remarks}

END,
updated_at = CASE id

    WHEN #{item.id} THEN #{item.updatedAt}

END,
updated_by = CASE id

    WHEN #{item.id} THEN #{item.updatedBy}

END
WHERE id IN

    #{item.id}
